class Solution:
    def count(self, num1: str, num2: str, min_sum: int, max_sum: int) -> int:
        MOD = 10**9 + 7

        def digit_sum(n: str) -> int:
            return sum(int(c) for c in n)

        def count_less_or_equal(n: str, target_sum: int) -> int:
            n = list(map(int, n))
            dp = [0] * (len(n) + 1)
            dp[0] = 1
            for i in range(len(n)):
                for j in range(10):
                    if j <= n[i]:
                        dp[i + 1] += dp[i]
                        if j != 0:
                            dp[i + 1] += dp[i] * (j - 1)
                        dp[i + 1] %= MOD
            return dp[len(n)]

        def count_in_range(n: str, min_s: int, max_s: int) -> int:
            return (count_less_or_equal(n, max_s) - count_less_or_equal(n, min_s - 1)) % MOD

        return (count_in_range(num2, min_sum, max_sum) - count_in_range(num1, min_sum, max_sum) + MOD) % MOD
